import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjLabel } from "./OjLabel";
export { OjLabel };

/**
 * Create an instance of [[OjLabel]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojLabel(driver, By.id('my-oj-label'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojLabel(driver: DriverLike, by: By): Promise<OjLabel> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjLabel
  if (!(webEl instanceof OjLabel)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-label>`);
  }
  return webEl;
}

register("oj-label", OjLabel);
